/* c4.h — Connect Four bitboard rules kernel.
 *
 * Layout: 7 columns x 6 rows; bit index = col*7 + row, row 0 at the
 * bottom.  Bit col*7+6 is a sentinel row that stays empty forever, so
 * one-dimensional shift tricks never wrap between columns.
 * Red moves first; red is to move exactly when moves is even.
 */
#ifndef C4_H
#define C4_H

#include <stdint.h>

typedef struct { uint64_t red; uint64_t yel; int moves; } c4;

void    c4_init(c4 *p);
int     c4_drop(c4 *p, int col);
int     c4_encode(c4 *p, const char *moves);
int     c4_win(uint64_t bb);
uint8_t c4_legal(const c4 *p);
long    c4_perft(const c4 *p, int depth);

#endif /* C4_H */
```

