#define C4_COLMASK(col) (0x3FULL << ((col) * 7)) /* rows 0..5 of a col */

void c4_init(c4 *p) {
    p->red = 0;
    p->yel = 0;
    p->moves = 0;
}

int c4_win(uint64_t bb) {
    uint64_t x;
    x = bb & (bb >> 1);  if (x & (x >> 2))  return 1; /* vertical   */
    x = bb & (bb >> 7);  if (x & (x >> 14)) return 1; /* horizontal */
    x = bb & (bb >> 6);  if (x & (x >> 12)) return 1; /* diagonal / */
    x = bb & (bb >> 8);  if (x & (x >> 16)) return 1; /* diagonal \ */
    return 0;
}

static int c4_over(const c4 *p) {
    return p->moves >= 42 || c4_win(p->red) || c4_win(p->yel);
}

