```c
static int reload_pair(config *c, const char *key, const char *val) {
    cfg_entry *e = find_entry(c, key);
    if (e != NULL) {
        e->live = 1;
        if (strcmp(e->value, val) == 0)
            return 0; /* value unchanged, keep it as is */
        char *nv = pool_take(c->pool, val);
        if (nv == NULL)
            return -1; /* old value stays put */
        pool_drop(c->pool, e->value);
        e->value = nv;
        return 0;
    }
    return add_entry(c, key, val);
}

int cfg_reload(config *c, const char *text) {
    if (c == NULL || text == NULL)
        return -1;

    /* Every setting is presumed gone until the new file mentions it. */
    for (size_t i = 0; i < c->count; i++)
        c->entries[i].live = 0;

    if (for_each_pair(c, text, reload_pair) != 0)
        return -1;

    /* Settings the new file never mentioned: hand their storage back and
     * close the gaps in the table. */
    size_t w = 0;
    for (size_t i = 0; i < c->count; i++) {
        if (c->entries[i].live) {
            c->entries[w++] = c->entries[i];
        } else {
            pool_drop(c->pool, c->entries[i].value);
        }
    }
    c->count = w;
    return 0;
}
