        return 0;                    /* end of input */

    for (;;) {
        size_t fstart, flen;

        if (nf == max_fields)
            return -1;               /* more fields than the caller can hold */

        if (i < buflen && buf[i] == '"') {
            /* Quoted field: the quote must be the field's first byte.
             * Decode in place: read at r, write at w (w <= r always),
             * collapsing doubled quotes into one literal quote.       */
            size_t r = i + 1;
            size_t w = r;            /* decoded content starts here   */
            int closed = 0;

            while (r < buflen) {
                if (buf[r] == '"') {
                    if (r + 1 < buflen && buf[r + 1] == '"') {
                        buf[w++] = '"';
                        r += 2;
                    } else {
                        r++;         /* past the closing quote */
                        closed = 1;
                        break;
                    }
                } else {
                    buf[w++] = buf[r++];
                }
            }
            if (!closed)
                return -1;           /* quote never closed */

            fstart = i + 1;
            flen = w - (i + 1);

            /* After the closing quote only a comma, LF, CRLF, or the
             * end of the buffer may follow.                           */
            if (r >= buflen) {
                fields[nf].start = fstart;
                fields[nf].len = flen;
                nf++;
                i = r;
                *pos = i;
                return (int)nf;
            }
            if (buf[r] == ',') {
                fields[nf].start = fstart;
                fields[nf].len = flen;
                nf++;
                i = r + 1;
                continue;
            }
            if (buf[r] == '\n') {
                fields[nf].start = fstart;
                fields[nf].len = flen;
                nf++;
                *pos = r + 1;
                return (int)nf;
            }
            if (buf[r] == '\r' && r + 1 < buflen && buf[r + 1] == '\n') {
                fields[nf].start = fstart;
                fields[nf].len = flen;
                nf++;
                *pos = r + 2;
                return (int)nf;
            }
            return -1;               /* junk after the closing quote */
        } else {
            /* Unquoted field: runs to the next comma, LF, CRLF, or the
             * end of the buffer. A lone CR (even at buffer end) and a
             * quote past the first byte are ordinary data.            */
            size_t j = i;

            while (j < buflen) {
                char c = buf[j];
                if (c == ',' || c == '\n')
                    break;
                if (c == '\r' && j + 1 < buflen && buf[j + 1] == '\n')
                    break;
                j++;
            }

            fields[nf].start = i;
            fields[nf].len = j - i;
            nf++;

            if (j >= buflen) {
                *pos = j;
                return (int)nf;
            }
            if (buf[j] == ',') {
                i = j + 1;
                continue;
            }
            if (buf[j] == '\n') {
                *pos = j + 1;
                return (int)nf;
            }
            /* buf[j] == '\r' followed by '\n' */
            *pos = j + 2;
            return (int)nf;
        }
    }
}
