```c
/* dynarray.h — generic growable array (void* + element size), C17.
 *
 * The array owns only its buffer; elements are copied in by value.
 * If elements themselves point at heap memory, freeing those pointees
 * is the caller's responsibility — da_free never chases them.
 *
 * da_get returns a pointer INTO the array; any da_push/da_insert may
 * reallocate the buffer, invalidating previously returned pointers.
 */
#ifndef DYNARRAY_H
#define DYNARRAY_H

#include <stddef.h>

typedef struct {
    void  *data;
    size_t len;        /* elements in use */
    size_t cap;        /* elements allocated */
    size_t elem_size;
} dynarray;

int    da_init(dynarray *da, size_t elem_size);   /* 0 ok; -1 if elem_size == 0 */
void   da_free(dynarray *da);
int    da_push(dynarray *da, const void *elem);   /* 0 ok; -1 on alloc failure */
int    da_pop(dynarray *da, void *out);           /* 0 ok; -1 if empty */
int    da_insert(dynarray *da, size_t idx, const void *elem); /* -1 if idx > len */
void  *da_get(const dynarray *da, size_t idx);    /* NULL if idx >= len */
size_t da_len(const dynarray *da);
size_t da_cap(const dynarray *da);

#endif /* DYNARRAY_H */
