```c
#include "dynarray.h"

#include <stdint.h>
#include <stdlib.h>
#include <string.h>

#define DA_INITIAL_CAP 8

int da_init(dynarray *da, size_t elem_size) {
    if (elem_size == 0)
        return -1;
    da->data = NULL;
    da->len = 0;
    da->cap = 0;
    da->elem_size = elem_size;
    return 0;
}

void da_free(dynarray *da) {
    free(da->data);
    da->data = NULL;
    da->len = 0;
    da->cap = 0;
    da->elem_size = 0;
}

/* Ensure room for at least `needed` elements. First allocation is
 * DA_INITIAL_CAP elements; capacity doubles from there. */
static int da_grow_to(dynarray *da, size_t needed) {
    if (da->cap >= needed)
        return 0;
    size_t newcap = da->cap ? da->cap : DA_INITIAL_CAP;
    while (newcap < needed) {
        if (newcap > SIZE_MAX / 2)
            return -1;
        newcap *= 2;
    }
    if (newcap > SIZE_MAX / da->elem_size)
        return -1;
    void *p = realloc(da->data, newcap * da->elem_size);
    if (!p)
        return -1;
    da->data = p;
    da->cap = newcap;
    return 0;
}

int da_push(dynarray *da, const void *elem) {
    return da_insert(da, da->len, elem);
}

int da_insert(dynarray *da, size_t idx, const void *elem) {
    if (idx > da->len)
        return -1;
    if (da_grow_to(da, da->len + 1) != 0)
        return -1;
    unsigned char *base = da->data;
    memmove(base + idx * da->elem_size,
            base + (idx + 1) * da->elem_size,
            (da->len - idx) * da->elem_size);
    memcpy(base + idx * da->elem_size, elem, da->elem_size);
    da->len++;
    return 0;
}
