#include "ini.h"

#include <string.h>

static int is_blank(char c) {
    return c == ' ' || c == '\t';
}

void ini_arena_init(ini_arena *a, void *storage, size_t cap) {
    a->base = (char *)storage;
    a->cap = cap;
    a->used = 0;
}

/* Bump-allocate n bytes; NULL when the block is exhausted. */
static char *arena_take(ini_arena *a, size_t n) {
    if (n > a->cap - a->used)
        return NULL;
    char *p = a->base + a->used;
    a->used += n;
    return p;
}

/* Copy len bytes plus a NUL terminator into the arena. */
static char *arena_copy(ini_arena *a, const char *s, size_t len) {
    char *p = arena_take(a, len + 1);
    if (p == NULL)
        return NULL;
    memcpy(p, s, len);
    p[len] = '\0';
    return p;
}
```

