long ini_parse(const char *text, ini_arena *a,
               ini_pair *pairs, size_t max_pairs,
               size_t *err_line, size_t *err_col) {
    if (text == NULL || a == NULL || pairs == NULL || max_pairs == 0)
        return INI_EARG;

    ini_parser p = { a, pairs, max_pairs, 0, NULL, 1 };
    const char *cur = text;

    for (;;) {
        const char *start = cur;
        const char *nl = strchr(cur, '\n');
        size_t len = nl ? (size_t)(nl - start) : strlen(start);
        if (len > 0 && start[len - 1] == '\r')
            len--;
        long rc = parse_line(&p, start, len, err_line, err_col);
        if (rc != INI_OK)
            return rc;
        if (nl == NULL)
            break;
        cur = nl + 1;
        p.line++;
    }

    if (err_line) *err_line = 0;
    if (err_col) *err_col = 0;
    return (long)p.count;
}
```

