            if (e != '"' && e != '\\' && e != 'n' && e != 't')
                return fail(err_line, err_col, lineno, i + 1, INI_EQUOTE);
            i += 2;
            n++;
            continue;
        }
        i++;
        n++;
    }
    return fail(err_line, err_col, lineno, q + 1, INI_EQUOTE);  /* unterminated */
