/* ini.c — single-pass, dependency-free INI scanner (C17).
 *
 * All output strings are copied into a caller-provided arena; the
 * scanner itself allocates nothing and keeps no state between calls.
 */
#include "ini.h"

#include <string.h>

static int is_blank(char c) {
    return c == ' ' || c == '\t';
}

static long report(size_t *err_line, size_t *err_col,
                   size_t line, size_t col, long code) {
    if (err_line != NULL)
        *err_line = line;
    if (err_col != NULL)
        *err_col = col;
    return code;
}

/* ---- arena ---------------------------------------------------------- */

void ini_arena_init(ini_arena *a, void *storage, size_t cap) {
    a->base = (char *)storage;
    a->cap = cap;
    a->used = 0;
}

static char *arena_take(ini_arena *a, size_t n) {
    if (n > a->cap - a->used)
        return NULL;
    {
        char *p = a->base + a->used;
        a->used += n;
        return p;
    }
}

static char *arena_copy(ini_arena *a, const char *s, size_t len) {
    char *p = arena_take(a, len + 1);
    if (p == NULL)
        return NULL;
    memcpy(p, s, len);
    p[len] = '\0';
    return p;
}

/* ---- parser state --------------------------------------------------- */

typedef struct {
    ini_arena *arena;
    ini_pair *pairs;
    size_t max_pairs;
    size_t count;
    const char *section;  /* arena-owned name; NULL until first set */
    size_t line;          /* 1-based number of the line being scanned */
} ini_parser;
