/* Validate the quoted value whose opening quote is line[q]; the trimmed
 * value ends at ve. On success *decoded holds the length of the value
 * after escape decoding. Columns are 1-based byte positions. */
static long scan_quoted(const char *line, size_t ve, size_t q,
                        size_t *decoded, size_t lineno,
                        size_t *err_line, size_t *err_col) {
    size_t i = q + 1;
    size_t n = 0;

    while (i < ve) {
        char c = line[i];

        if (c == '"') {
            size_t t = i + 1;
            while (t < ve && is_blank(line[t]))
                t++;
            if (t < ve)
                return report(err_line, err_col, lineno, t + 1, INI_ETRAIL);
            *decoded = n;
            return INI_OK;
        }
        if (c == '\\') {
            char e;
            if (i + 1 >= ve)
                return report(err_line, err_col, lineno, i + 1, INI_EQUOTE);
            e = line[i + 1];
            if (e != '"' && e != '\\' && e != 'n' && e != 't')
                return report(err_line, err_col, lineno, i + 1, INI_EQUOTE);
            i += 2;
            n++;
            continue;
        }
        i++;
        n++;
    }
    return report(err_line, err_col, lineno, q + 1, INI_EQUOTE);
}

/* Copy a previously validated quoted value into the arena, decoding the
 * four escapes. Exactly decoded + 1 bytes are consumed. */
static char *arena_copy_quoted(ini_arena *a, const char *line, size_t q,
                               size_t decoded) {
    char *dst = arena_take(a, decoded + 1);
    size_t i = q + 1;
    size_t w = 0;
    char c;

    if (dst == NULL)
        return NULL;
    while ((c = line[i]) != '"') {
        if (c == '\\') {
            char e = line[i + 1];
            dst[w++] = (e == 'n') ? '\n' : (e == 't') ? '\t' : e;
            i += 2;
        } else {
            dst[w++] = c;
            i++;
        }
    }
    dst[w] = '\0';
    return dst;
}
