static long parse_section(ini_parser *p, const char *line, size_t len,
                          size_t open, size_t *err_line, size_t *err_col) {
    size_t close = open + 1;
    size_t nb, ne, t;
    char *name;

    while (close < len && line[close] != ']')
        close++;
    if (close == len)
        return report(err_line, err_col, p->line, open + 1, INI_ESECTION);

    nb = open + 1;
    ne = close;
    while (nb < ne && is_blank(line[nb]))
        nb++;
    while (ne > nb && is_blank(line[ne - 1]))
        ne--;
    if (nb == ne)
        return report(err_line, err_col, p->line, open + 1, INI_ESECTION);

    t = close + 1;
    while (t < len && is_blank(line[t]))
        t++;
    if (t < len)
        return report(err_line, err_col, p->line, t + 1, INI_ESECTION);

    name = arena_copy(p->arena, line + nb, ne - nb);
    if (name == NULL)
        return report(err_line, err_col, p->line, 0, INI_ENOMEM);
    p->section = name;
    return INI_OK;
}
