```c
static long parse_pair(ini_parser *p, const char *line, size_t len,
                       size_t first, size_t *err_line, size_t *err_col) {
    size_t eq = first;
    size_t kb, ke, vb, ve;
    size_t decoded = 0;
    int quoted;
    const char *section;
    char *key, *value;
    ini_pair *pair;

    while (eq < len && line[eq] != '=')
        eq++;
    if (eq == len)
        return report(err_line, err_col, p->line, first + 1, INI_EKEY);

    kb = first;
    ke = eq;
    while (ke > kb && is_blank(line[ke - 1]))
        ke--;
    if (kb == ke)
        return report(err_line, err_col, p->line, eq + 1, INI_EKEY);

    vb = eq + 1;
    ve = len;
    while (vb < ve && is_blank(line[vb]))
        vb++;
    while (ve > vb && is_blank(line[ve - 1]))
        ve--;

    quoted = (vb < ve && line[vb] == '"');
    if (quoted) {
        long rc = scan_quoted(line, ve, vb, &decoded, p->line,
                              err_line, err_col);
        if (rc != INI_OK)
            return rc;
    }

    /* The line is a valid pair; make sure there is room for it. */
    if (p->count == p->max_pairs)
        return report(err_line, err_col, p->line, 0, INI_ENOMEM);

    if (p->section == NULL) {
        p->section = arena_copy(p->arena, "", 0);
        if (p->section == NULL)
            return report(err_line, err_col, p->line, 0, INI_ENOMEM);
    }
    section = p->section;

    key = arena_copy(p->arena, line + kb, ke - kb);
    if (key == NULL)
        return report(err_line, err_col, p->line, 0, INI_ENOMEM);

    if (quoted) {
        value = arena_copy_quoted(p->arena, line, vb, decoded);
    } else {
        value = arena_copy(p->arena, line + vb, ve - vb);
    }
    if (value == NULL)
        return report(err_line, err_col, p->line, 0, INI_ENOMEM);

    pair = &p->pairs[p->count++];
    pair->section = section;
    pair->key = key;
    pair->value = value;
    pair->line = p->line;
    return INI_OK;
}
