/* kvunesc.c — see kvunesc.h for the contract. */
#include "kvunesc.h"

/* Value of a hex digit, or -1 if c is not one. Either case is accepted. */
static int hex_value(unsigned char c)
{
    if (c >= '0' && c <= '9') return (int)(c - '0');
    if (c >= 'a' && c <= 'f') return (int)(c - 'a') + 10;
    if (c >= 'A' && c <= 'F') return (int)(c - 'A') + 10;
    return -1;
}

kv_result kv_decode_value(const char *src, size_t start_line, size_t start_col,
                          char *out, size_t outsz)
{
    kv_result r = { KV_OK, 0, 0, 0, 0 };
    size_t i = 0;                 /* cursor into src */
    size_t line = start_line;     /* physical line of src[i] */
    size_t col = start_col;       /* byte column of src[i] */
    size_t n = 0;                 /* decoded bytes written */
    size_t cap = (outsz > 0) ? outsz - 1 : 0; /* data room, NUL reserved */

    for (;;) {
        unsigned char c = (unsigned char)src[i];

        if (c == '\0' || c == '\n')
            break;                          /* terminator, not consumed */

        if (c != '\\') {                    /* literal byte */
            if (n == cap)
                goto nospace;
            out[n++] = (char)c;
            i++;
            col++;
            continue;
        }

        /* An escape opens at src[i]; remember where for error reports. */
        {
            size_t bs_line = line;
            size_t bs_col = col;
            unsigned char e = (unsigned char)src[i + 1];

            if (e == '\0') {
                r.status = KV_ERR_TRAILING_BACKSLASH;
                r.err_line = bs_line;
                r.err_col = bs_col;
                goto fail;
            }
            if (e == '\n') {
                /* Continuation: drop backslash, newline and the indent. */
                i += 2;
                line++;
                col = 1;
                while (src[i] == ' ' || src[i] == '\t') {
                    i++;
                    col++;
                }
                continue;
            }
            if (e == 'n' || e == 't' || e == '\\') {
                char v = (e == 'n') ? '\n' : (e == 't') ? '\t' : '\\';
                if (n == cap)
                    goto nospace;
                out[n++] = v;
                i += 2;
                col += 2;
                continue;
            }
            if (e == 'x') {
                unsigned char d1 = (unsigned char)src[i + 2];
                unsigned char d2;
                int hi, lo;
                if (d1 == '\0' || d1 == '\n')
                    goto truncated;
                hi = hex_value(d1);
                if (hi < 0)
                    goto badhex;
                d2 = (unsigned char)src[i + 3];
                if (d2 == '\0' || d2 == '\n')
                    goto truncated;
                lo = hex_value(d2);
                if (lo < 0)
                    goto badhex;
                if (n == cap)
                    goto nospace;
                out[n++] = (char)(unsigned char)(hi * 16 + lo);
                i += 4;
                col += 4;
                continue;
            badhex:
                r.status = KV_ERR_BAD_HEX;
                r.err_line = bs_line;
                r.err_col = bs_col;
                goto fail;
            truncated:
                r.status = KV_ERR_TRUNCATED_HEX;
                r.err_line = bs_line;
                r.err_col = bs_col;
                goto fail;
            }
            r.status = KV_ERR_UNKNOWN_ESCAPE;
            r.err_line = bs_line;
            r.err_col = bs_col;
            goto fail;
        }
    }

    if (outsz == 0)
        goto nospace;                       /* no room even for the NUL */
    r.consumed = i;
    r.out_len = n;
    out[n] = '\0';
    return r;

nospace:
    r.status = KV_ERR_NOSPACE;              /* no position for this one */
fail:
    r.consumed = 0;
    r.out_len = 0;
    if (outsz > 0)
        out[0] = '\0';
    return r;
}
