ringbuf.h:

```c
/* ringbuf.h -- fixed-capacity byte ring buffer over caller-owned storage.
 *
 * C17, freestanding-friendly: needs only <stddef.h> (size_t).  The ring
 * never allocates; the caller hands in storage in rb_init() and owns it
 * for the ring's whole life.  All state lives in the struct, so any
 * number of rings can run side by side without interfering.
 */
#ifndef RINGBUF_H
#define RINGBUF_H

#include <stddef.h>

typedef struct {
    unsigned char *buf;   /* caller's storage, cap bytes */
    size_t cap;
    size_t head;          /* index of the oldest byte */
    size_t count;         /* bytes currently stored */
    size_t high;          /* largest count ever seen */
} ringbuf;

/* Prepare rb to use storage[0..cap).  Returns 0 on success, -1 if
 * storage is NULL or cap is 0. */
int    rb_init(ringbuf *rb, void *storage, size_t cap);

/* Append up to n bytes from src, oldest-position first.  Returns how
 * many were accepted: min(n, free space).  On a partial write the front
 * of src is kept and the tail dropped. */
size_t rb_write(ringbuf *rb, const void *src, size_t n);

/* Copy out up to n of the oldest bytes in FIFO order and remove them.
 * Returns how many were removed: min(n, count). */
size_t rb_read(ringbuf *rb, void *dst, size_t n);

/* Like rb_read but consumes nothing. */
size_t rb_peek(const ringbuf *rb, void *dst, size_t n);

size_t rb_len(const ringbuf *rb);    /* bytes currently stored        */
size_t rb_avail(const ringbuf *rb);  /* free space: cap - count       */
size_t rb_high(const ringbuf *rb);   /* high-water mark, only ratchets up */

/* Drop all stored bytes (count -> 0).  Does not reset the watermark. */
void   rb_clear(ringbuf *rb);

#endif /* RINGBUF_H */
```

ringbuf.c:

```c
#include "ringbuf.h"

#include <string.h>

int rb_init(ringbuf *rb, void *storage, size_t cap) {
    if (storage == NULL || cap == 0)
        return -1;
    rb->buf = storage;
    rb->cap = cap;
    rb->head = 0;
    rb->count = 0;
    rb->high = 0;
    return 0;
}

size_t rb_write(ringbuf *rb, const void *src, size_t n) {
    size_t free_space = rb->cap - rb->count;
    size_t accept = n < free_space ? n : free_space;
    if (accept == 0)
        return 0;

    size_t tail = (rb->head + rb->count) % rb->cap;
    size_t first = rb->cap - tail;      /* bytes from tail to end of storage */
    if (first > accept)
        first = accept;
    memcpy(rb->buf + tail, src, first);
    memcpy(rb->buf, (const unsigned char *)src + first, accept - first);

    rb->count += accept;
    if (rb->count > rb->high)
        rb->high = rb->count;
    return accept;
}
```

Read/peek share a copy-out helper:

```c
static size_t copy_out(const ringbuf *rb, void *dst, size_t n) {
    size_t got = n < rb->count ? n : rb->count;
    if (got == 0)
        return 0;

    size_t first = rb->cap - rb->head;  /* bytes from head to end of storage */
    if (first > got)
        first = got;
    memcpy(dst, rb->buf + rb->head, first);
    memcpy((unsigned char *)dst + first, rb->buf, got - first);
    return got;
}

size_t rb_read(ringbuf *rb, void *dst, size_t n) {
    size_t got = copy_out(rb, dst, n);
    rb->head = (rb->head + got) % rb->cap;
    rb->count -= got;
    return got;
}

size_t rb_peek(const ringbuf *rb, void *dst, size_t n) {
    return copy_out(rb, dst, n);
}
```

