int snake_tick(snake *s) {
    if (s == NULL || !s->alive) return -1;
    int dx = 0, dy = 0;
    switch (s->pending) {
        case 'N': dy = -1; break;
        case 'S': dy = 1; break;
        case 'E': dx = 1; break;
        case 'W': dx = -1; break;
        default: break; /* cannot happen */
    }
    int nx = s->bx[s->head] + dx;
    int ny = s->by[s->head] + dy;
    if (nx < 0 || nx >= s->w || ny < 0 || ny >= s->h) {
        s->alive = 0;
        return 0;
    }
    int eating = s->food_next < s->food_count &&
                 nx == s->fx[s->food_next] && ny == s->fy[s->food_next];
    /* cells that stay occupied after the move: all len cells when eating
       (tail holds), the front len-1 when not (tail vacates) */
    int occupied = eating ? s->len : s->len - 1;
    for (int i = 0; i < occupied; i++) {
        int idx = (s->head - i + SNAKE_CAP) % SNAKE_CAP;
        if (s->bx[idx] == nx && s->by[idx] == ny) {
            s->alive = 0;
            return 0;
        }
    }
    s->head = (s->head + 1) % SNAKE_CAP;
    s->bx[s->head] = (uint8_t)nx;
    s->by[s->head] = (uint8_t)ny;
    s->moved = s->pending;
    if (eating) {
        s->len++;
        s->score++;
        s->food_next++;
        return 2;
    }
    return 1;
}
```

