/* tttbit.h — bitboard tic-tac-toe: rules, perfect-play solver, state census.
 *
 * A board is two 9-bit masks: bit i is cell i in row-major order
 * (0 = top-left, 8 = bottom-right).  x marks cells held by X, o by O.
 * No I/O, no allocation; C17 + <stdint.h> only.
 */
#ifndef TTTBIT_H
#define TTTBIT_H

#include <stdint.h>

/* The eight winning lines, fixed order: rows top-to-bottom (0-2),
 * columns left-to-right (3-5), 0-4-8 diagonal (6), 2-4-6 diagonal (7).
 * Any other index yields 0. */
uint16_t ttt_line(int i);

/* 1 when m holds all three bits of at least one winning line, else 0. */
int ttt_has_win(uint16_t m);

/* Mask of empty, playable cells; 0 once the game is over (a side has a
 * line, or the board is full). */
uint16_t ttt_moves(uint16_t x, uint16_t o);

/* Perfect-play value from this position: +1 X wins, -1 O wins, 0 draw.
 * xturn is 1 when X moves next, 0 when O does.  Terminal positions score
 * themselves regardless of xturn. */
int ttt_value(uint16_t x, uint16_t o, int xturn);

/* Optimal cell for the side to move (max value for X, min for O), ties
 * broken by lowest cell index; -1 when the game is over. */
int ttt_best(uint16_t x, uint16_t o, int xturn);

/* Distinct positions reachable from the empty board by alternating legal
 * play (X first), stopping at game over; the empty board and terminal
 * positions are included.  Out-pointers (any may be 0) receive the counts
 * of X-wins, O-wins and full-board draws among them. */
long ttt_reachable(long *xwins, long *owins, long *draws);

#endif /* TTTBIT_H */
```

