```c
#include "tttbit.h"

#include <stdint.h>

#define FULL 0x1FFu          /* all nine cells */
#define NCODES 19683         /* 3^9 ternary board codes */

static const uint16_t LINES[8] = {
    0x007u, 0x038u, 0x1C0u,  /* rows, top to bottom */
    0x049u, 0x092u, 0x124u,  /* columns, left to right */
    0x111u,                  /* diagonal 0-4-8 */
    0x054u                   /* diagonal 2-4-6 */
};

uint16_t ttt_line(int i) {
    if (i < 0 || i > 7) return 0;
    return LINES[i];
}

int ttt_has_win(uint16_t m) {
    for (int i = 0; i < 8; i++)
        if ((m & LINES[i]) == LINES[i]) return 1;
    return 0;
}

uint16_t ttt_moves(uint16_t x, uint16_t o) {
    if (ttt_has_win(x) || ttt_has_win(o)) return 0;
    return (uint16_t)(~(x | o) & FULL);
}

/* Ternary board code: cell i contributes digit 0 (empty), 1 (X) or 2 (O)
 * times 3^i, giving a unique index in [0, 3^9). */
static int encode(uint16_t x, uint16_t o) {
    int code = 0;
    for (int i = 0, pow3 = 1; i < 9; i++, pow3 *= 3) {
        if (x & (uint16_t)(1u << i)) code += pow3;
        else if (o & (uint16_t)(1u << i)) code += 2 * pow3;
    }
    return code;
}

/* Minimax memo: one table per side to move over the 3^9 board codes.
 * Entries hold value + 2; 0 means "not computed yet" (static zero-init),
 * so values -1/0/+1 map to 1/2/3. */
static int8_t vmemo[2][NCODES];

static int solve(uint16_t x, uint16_t o, int xturn) {
    if (ttt_has_win(x)) return 1;
    if (ttt_has_win(o)) return -1;
    uint16_t open = (uint16_t)(~(x | o) & FULL);
    if (!open) return 0;

    int8_t *slot = &vmemo[xturn ? 1 : 0][encode(x, o)];
    if (*slot) return *slot - 2;

    int best = xturn ? -2 : 2;
    for (int i = 0; i < 9; i++) {
        uint16_t bit = (uint16_t)(1u << i);
        if (!(open & bit)) continue;
        int v = xturn ? solve((uint16_t)(x | bit), o, 0)
                      : solve(x, (uint16_t)(o | bit), 1);
        if (xturn ? v > best : v < best) best = v;
    }
    *slot = (int8_t)(best + 2);
    return best;
}

int ttt_value(uint16_t x, uint16_t o, int xturn) {
    return solve(x, o, xturn);
}

int ttt_best(uint16_t x, uint16_t o, int xturn) {
    uint16_t open = ttt_moves(x, o);
    if (!open) return -1;

    int cell = -1;
    int best = xturn ? -2 : 2;
    for (int i = 0; i < 9; i++) {           /* lowest index wins ties */
        uint16_t bit = (uint16_t)(1u << i);
        if (!(open & bit)) continue;
        int v = xturn ? solve((uint16_t)(x | bit), o, 0)
                      : solve(x, (uint16_t)(o | bit), 1);
        if (cell < 0 || (xturn ? v > best : v < best)) {
            cell = i;
            best = v;
        }
    }
    return cell;
}

/* Reachability census: DFS from the empty board, deduped by board code. */
static uint8_t seen[NCODES];
static long n_total, n_xwins, n_owins, n_draws;

static void census(uint16_t x, uint16_t o, int xturn) {
    uint16_t open = ttt_moves(x, o);
    if (!open) {                            /* terminal: classify it */
        if (ttt_has_win(x)) n_xwins++;
        else if (ttt_has_win(o)) n_owins++;
        else n_draws++;
        return;
    }
    for (int i = 0; i < 9; i++) {
        uint16_t bit = (uint16_t)(1u << i);
        if (!(open & bit)) continue;
        uint16_t nx = xturn ? (uint16_t)(x | bit) : x;
        uint16_t no = xturn ? o : (uint16_t)(o | bit);
        int code = encode(nx, no);
        if (!seen[code]) {
            seen[code] = 1;
            n_total++;
            census(nx, no, !xturn);
        }
    }
}

long ttt_reachable(long *xwins, long *owins, long *draws) {
    for (int i = 0; i < NCODES; i++) seen[i] = 0;   /* idempotent re-runs */
    seen[0] = 1;
    n_total = 1;                            /* the empty board itself */
    n_xwins = n_owins = n_draws = 0;
    census(0, 0, 1);
    if (xwins) *xwins = n_xwins;
    if (owins) *owins = n_owins;
    if (draws) *draws = n_draws;
    return n_total;
}
```

