bool square_attacked(const char *b, int sq, bool by_white) {
    int f = file_of(sq), r = rank_of(sq);
    // pawns
    if (by_white) {
        if (r > 0) {
            if (f > 0 && b[sq - 9] == 'P') return true;
            if (f < 7 && b[sq - 7] == 'P') return true;
        }
    } else {
        if (r < 7) {
            if (f > 0 && b[sq + 7] == 'p') return true;
            if (f < 7 && b[sq + 9] == 'p') return true;
        }
    }
    // knights
    static const int kn[8][2] = {{1,2},{2,1},{2,-1},{1,-2},{-1,-2},{-2,-1},{-2,1},{-1,2}};
    char n = by_white ? 'N' : 'n';
    for (auto &d : kn) {
        int nf = f + d[0], nr = r + d[1];
        if (nf >= 0 && nf < 8 && nr >= 0 && nr < 8 && b[nr*8+nf] == n) return true;
    }
    // king
    char k = by_white ? 'K' : 'k';
    for (int df = -1; df <= 1; df++) for (int dr = -1; dr <= 1; dr++) {
        if (!df && !dr) continue;
        int nf = f+df, nr = r+dr;
        if (nf>=0&&nf<8&&nr>=0&&nr<8&&b[nr*8+nf]==k) return true;
    }
    // sliders
    static const int rookdirs[4][2] = {{1,0},{-1,0},{0,1},{0,-1}};
    static const int bishdirs[4][2] = {{1,1},{1,-1},{-1,1},{-1,-1}};
    char rq = by_white ? 'R' : 'r', qq = by_white ? 'Q' : 'q';
    char bb = by_white ? 'B' : 'b';
    for (auto &d : rookdirs) {
        int nf = f, nr = r;
        for (;;) {
            nf += d[0]; nr += d[1];
            if (nf<0||nf>7||nr<0||nr>7) break;
            char p = b[nr*8+nf];
            if (p != '.') { if (p == rq || p == qq) return true; break; }
        }
