```cpp
int WaitList::sweep_holds(int now) {
    auto lapsed = [now](const Visit &v) { return v.hold_until <= now; };
    auto first_lapsed = std::remove_if(queue_.begin(), queue_.end(), lapsed);
    int dropped = static_cast<int>(queue_.end() - first_lapsed);
    queue_.erase(first_lapsed, queue_.end());
    by_ticket_.clear();
    for (std::size_t i = 0; i < queue_.size(); i++)
        by_ticket_[queue_[i].ticket] = i;
    dropped_total_ += dropped;
    return dropped;
}
