Outcome applyBinary(const std::string& op, const Value& l, const Value& r) {
    if (op == "+") {
        return std::visit(
            Overloaded{
                [](long a, long b) -> Outcome { return Value(a + b); },
                [](const std::string& a, const std::string& b) -> Outcome {
                    return Value(a + b);
                },
                [](const auto&, const auto&) -> Outcome {
                    return EvalError{"type", "+"};
                },
            },
            l, r);
    }
    if (op == "-" || op == "*") {
        const long* a = std::get_if<long>(&l);
        const long* b = std::get_if<long>(&r);
        if (a == nullptr || b == nullptr) return EvalError{"type", op};
        return Value(op == "-" ? *a - *b : *a * *b);
    }
    if (op == "/") {
        const long* a = std::get_if<long>(&l);
        const long* b = std::get_if<long>(&r);
        if (a == nullptr || b == nullptr) return EvalError{"type", "/"};
        if (*b == 0) return EvalError{"div0", ""};
        /* The single UB corner of C++ integer division: LONG_MIN / -1
         * faults on common hardware. Wrap, like the other operators. */
        if (*a == std::numeric_limits<long>::min() && *b == -1)
            return Value(std::numeric_limits<long>::min());
        return Value(*a / *b);
    }
    if (op == "==" || op == "!=") {
        if (l.index() != r.index()) return EvalError{"type", op};
        const bool eq = (l == r);
        return Value(op == "==" ? eq : !eq);
    }
    if (op == "<") {
        return std::visit(
            Overloaded{
                [](long a, long b) -> Outcome { return Value(a < b); },
                [](const std::string& a, const std::string& b) -> Outcome {
                    return Value(a < b);
                },
                [](const auto&, const auto&) -> Outcome {
                    return EvalError{"type", "<"};
                },
            },
            l, r);
    }
    return EvalError{"type", op};
}
