Outcome eval(const ExprPtr& e, const Env& env) {
    return std::visit(
        Overloaded{
            [](const Lit& n) -> Outcome { return n.v; },
            [&env](const Ref& n) -> Outcome {
                const auto it = env.find(n.name);
                if (it == env.end()) return EvalError{"undef", n.name};
                return it->second;
            },
            [&env](const Unary& n) -> Outcome {
                Outcome operand = eval(n.operand, env);
                if (const EvalError* err = std::get_if<EvalError>(&operand))
                    return *err;
                return applyUnary(n.op, std::get<Value>(operand));
            },
            [&env](const Binary& n) -> Outcome {
                Outcome lhs = eval(n.lhs, env);
                if (const EvalError* err = std::get_if<EvalError>(&lhs))
                    return *err;
                const Value& lv = std::get<Value>(lhs);

                if (n.op == "and" || n.op == "or") {
                    const bool* lb = std::get_if<bool>(&lv);
                    if (lb == nullptr) return EvalError{"type", n.op};
                    if ((n.op == "and" && !*lb) || (n.op == "or" && *lb))
                        return Value(*lb);
                    Outcome rhs = eval(n.rhs, env);
                    if (const EvalError* err = std::get_if<EvalError>(&rhs))
                        return *err;
                    const bool* rb = std::get_if<bool>(&std::get<Value>(rhs));
                    if (rb == nullptr) return EvalError{"type", n.op};
                    return Value(*rb);
                }

                Outcome rhs = eval(n.rhs, env);
                if (const EvalError* err = std::get_if<EvalError>(&rhs))
                    return *err;
                return applyBinary(n.op, lv, std::get<Value>(rhs));
            },
        },
        e->node);
}
