static const int DIRS[4][2] = {{0,1},{1,0},{1,1},{1,-1}};

void gm_init(Gomoku *g) {
    for (int r=0;r<15;r++) for(int c=0;c<15;c++) g->board[r][c]=0;
    g->to_move=1; g->winner=0; g->filled=0;
}

int gm_at(const Gomoku *g,int r,int c){
    if(r<0||r>=15||c<0||c>=15) return -1;
    return g->board[r][c];
}

int gm_to_move(const Gomoku *g){return g->to_move;}
int gm_winner(const Gomoku *g){return g->winner;}

// maximal contiguous run of `side` through (r,c) in direction (dr,dc),
// assuming board[r][c]==side
static int run_len(const Gomoku *g,int r,int c,int dr,int dc,int side){
    int n=1;
    for(int k=1;;k++){int rr=r+dr*k,cc=c+dc*k; if(rr<0||rr>=15||cc<0||cc>=15||g->board[rr][cc]!=side) break; n++;}
    for(int k=1;;k++){int rr=r-dr*k,cc=c-dc*k; if(rr<0||rr>=15||cc<0||cc>=15||g->board[rr][cc]!=side) break; n++;}
    return n;
}
```

