constexpr int kSize = 15;
constexpr int kDirs[4][2] = {{0, 1}, {1, 0}, {1, 1}, {1, -1}};

bool in_range(int r, int c) {
    return r >= 0 && r < kSize && c >= 0 && c < kSize;
}

/* Length of the maximal contiguous run of `side` stones through (r, c) in
 * direction (dr, dc), counting (r, c) itself as a stone of `side`. Works on
 * the board as-is, so it serves both real placements and hypotheticals. */
int run_through(const Gomoku *g, int r, int c, int dr, int dc, int side) {
    int n = 1;
    for (int k = 1; in_range(r + dr * k, c + dc * k) &&
                    g->board[r + dr * k][c + dc * k] == side; ++k)
        ++n;
    for (int k = 1; in_range(r - dr * k, c - dc * k) &&
                    g->board[r - dr * k][c - dc * k] == side; ++k)
        ++n;
    return n;
}

/* Would `side` placing at empty (r, c) produce a maximal run of exactly
 * `len` in any of the four directions? */
bool makes_run(const Gomoku *g, int r, int c, int side, int len) {
    for (const auto &d : kDirs)
        if (run_through(g, r, c, d[0], d[1], side) == len)
            return true;
    return false;
}

bool parse_move(const std::string &tok, int *r, int *c) {
    const char *first = tok.data();
    const char *last = first + tok.size();
    const char *comma = nullptr;
    for (const char *p = first; p != last; ++p)
        if (*p == ',') { comma = p; break; }
    if (comma == nullptr) return false;
    auto a = std::from_chars(first, comma, *r);
    if (a.ec != std::errc{} || a.ptr != comma) return false;
    auto b = std::from_chars(comma + 1, last, *c);
    if (b.ec != std::errc{} || b.ptr != last) return false;
    return true;
}

