                    case 2: hit = makes_run(g, r, c, me, 4); break;
                    default: hit = makes_run(g, r, c, opp, 4); break;
                }
                if (hit) { *r = r; *c = c; return true; }
            }
        }
    }
    // tier 5: center-most
    int bestR = -1, bestC = -1, bestD = kSize;
    for (int r = 0; r < kSize; ++r)
