       // form whether or not a T lives there, and the right destination for
       // std::construct_at.  Never laundered: std::launder on storage with no
       // live T is undefined behavior.
       T* slot(std::size_t b, std::size_t i) noexcept {
           return reinterpret_cast<T*>(arena_[b] + i * sizeof(T));
       }
       const T* slot(std::size_t b, std::size_t i) const noexcept {
           return reinterpret_cast<const T*>(arena_[b] + i * sizeof(T));
