/* Pyramid solitaire engine — C++20, standard library only. */
#ifndef PYRAMID_H
#define PYRAMID_H

#include <string>
#include <vector>

struct Pyramid {
    std::string card[7][7];        /* pyramid spots; only col <= row is used */
    bool present[7][7] = {};       /* false once a card has been removed */
    std::vector<std::string> stock; /* back() is the next card to draw */
    std::vector<std::string> waste; /* back() is the top of the waste */
    int recyclesUsed = 0;          /* the waste may be recycled at most twice */
};

bool pyr_load(Pyramid *g, const std::string &deal);
bool pyr_exposed(const Pyramid *g, int row, int col);
bool pyr_draw(Pyramid *g);
bool pyr_recycle(Pyramid *g);
bool pyr_remove(Pyramid *g, const std::string &a, const std::string &b);
bool pyr_remove_king(Pyramid *g, const std::string &spot);
int  pyr_stock_size(const Pyramid *g);
int  pyr_waste_size(const Pyramid *g);
std::string pyr_waste_top(const Pyramid *g);
int  pyr_state(const Pyramid *g);
std::string pyr_render(const Pyramid *g);

#endif /* PYRAMID_H */
```

