        default:  return card[0] - '0';  /* '2'..'9' */
    }
}

bool well_formed(const std::string &card) {
    if (card.size() != 2) return false;
    const char r = card[0], s = card[1];
    const bool rank_ok = r == 'A' || r == 'T' || r == 'J' || r == 'Q' || r == 'K'
                         || (r >= '2' && r <= '9');
    const bool suit_ok = s == 'C' || s == 'D' || s == 'H' || s == 'S';
    return rank_ok && suit_ok;
}

enum Spot { SPOT_BAD, SPOT_CELL, SPOT_WASTE };

/* Decode a removal spot: "Prc" (exposed pyramid card) or "W" (waste top). */
Spot decode_spot(const Pyramid *g, const std::string &s, int &row, int &col) {
    if (s == "W") return g->waste.empty() ? SPOT_BAD : SPOT_WASTE;
    if (s.size() == 3 && s[0] == 'P'
        && s[1] >= '0' && s[1] <= '6'
        && s[2] >= '0' && s[2] <= '9') {
        const int r = s[1] - '0', c = s[2] - '0';
        if (pyr_exposed(g, r, c)) { row = r; col = c; return SPOT_CELL; }
    }
    return SPOT_BAD;
}

int spot_value(const Pyramid *g, Spot kind, int row, int col) {
    return card_value(kind == SPOT_WASTE ? g->waste.back() : g->card[row][col]);
}

void clear_spot(Pyramid *g, Spot kind, int row, int col) {
    if (kind == SPOT_WASTE) g->waste.pop_back();
    else g->present[row][col] = false;
}

} /* namespace */

bool pyr_load(Pyramid *g, const std::string &deal) {
    std::istringstream in(deal);
    std::vector<std::string> deck;
    std::string tok;
    while (in >> tok) deck.push_back(tok);
    if (deck.size() != 52) return false;
    std::set<std::string> seen;
    for (const std::string &c : deck)
        if (!well_formed(c) || !seen.insert(c).second) return false;

    int k = 0;
    for (int r = 0; r < 7; ++r)
        for (int c = 0; c <= r; ++c) {
            g->card[r][c] = deck[k++];
            g->present[r][c] = true;
        }
    g->stock.clear();
    for (int i = 51; i >= 28; --i) g->stock.push_back(deck[i]); /* first token on top */
    g->waste.clear();
    g->recyclesUsed = 0;
    return true;
}

bool pyr_exposed(const Pyramid *g, int row, int col) {
    if (row < 0 || row > 6 || col < 0 || col > row) return false;
    if (!g->present[row][col]) return false;
    if (row == 6) return true;
    return !g->present[row + 1][col] && !g->present[row + 1][col + 1];
}

bool pyr_draw(Pyramid *g) {
    if (g->stock.empty()) return false;
    g->waste.push_back(g->stock.back());
    g->stock.pop_back();
    return true;
}

bool pyr_recycle(Pyramid *g) {
    if (!g->stock.empty() || g->waste.empty() || g->recyclesUsed >= 2) return false;
    /* Flip the waste back onto the stock so the same cards come out
     * in the same order as the first time through. */
    g->stock.assign(g->waste.rbegin(), g->waste.rend());
    g->waste.clear();
    ++g->recyclesUsed;
    return true;
}

bool pyr_remove(Pyramid *g, const std::string &a, const std::string &b) {
    if (a == b) return false;
    int ra = 0, ca = 0, rb = 0, cb = 0;
    const Spot ka = decode_spot(g, a, ra, ca);
    const Spot kb = decode_spot(g, b, rb, cb);
    if (ka == SPOT_BAD || kb == SPOT_BAD) return false;
    if (spot_value(g, ka, ra, ca) + spot_value(g, kb, rb, cb) != 13) return false;
    clear_spot(g, ka, ra, ca);
    clear_spot(g, kb, rb, cb);
    return true;
}

bool pyr_remove_king(Pyramid *g, const std::string &spot) {
    int r = 0, c = 0;
    const Spot k = decode_spot(g, spot, r, c);
    if (k == SPOT_BAD || spot_value(g, k, r, c) != 13) return false;
    clear_spot(g, k, r, c);
    return true;
}

int pyr_stock_size(const Pyramid *g) { return (int)g->stock.size(); }
int pyr_waste_size(const Pyramid *g) { return (int)g->waste.size(); }

std::string pyr_waste_top(const Pyramid *g) {
    return g->waste.empty() ? std::string() : g->waste.back();
}

int pyr_state(const Pyramid *g) {
    bool any_left = false;
    for (int r = 0; r < 7 && !any_left; ++r)
        for (int c = 0; c <= r; ++c)
            if (g->present[r][c]) { any_left = true; break; }
    if (!any_left) return 1;

    const bool can_recycle = g->stock.empty() && !g->waste.empty() && g->recyclesUsed < 2;
    if (!g->stock.empty() || can_recycle) return 0;

    /* Stock is dry and no recycle remains: stuck unless a move exists. */
    std::vector<int> open;
    for (int r = 0; r < 7; ++r)
        for (int c = 0; c <= r; ++c)
            if (pyr_exposed(g, r, c)) open.push_back(card_value(g->card[r][c]));
    if (!g->waste.empty()) open.push_back(card_value(g->waste.back()));
    for (std::size_t i = 0; i < open.size(); ++i) {
        if (open[i] == 13) return 0;              /* a king can always leave */
        for (std::size_t j = i + 1; j < open.size(); ++j)
            if (open[i] + open[j] == 13) return 0;
    }
    return 2;
}

std::string pyr_render(const Pyramid *g) {
    std::string out;
    for (int r = 0; r < 7; ++r) {
        out.append(2 * (6 - r), ' ');
        for (int c = 0; c <= r; ++c) {
            if (c) out += "  ";
            out += g->present[r][c] ? g->card[r][c] : "--";
        }
        out += '\n';
    }
    return out;
}
