```cpp
/* RAII guards for the bench action journal.
 *
 * The in-process layer never touches hardware; it appends action lines
 * ("open <path>", "close <path>", "lock <name>", "unlock <name>") to an
 * ActionLog and the bench daemon replays them. These guards make sure
 * every acquisition is matched by exactly one release line, in reverse
 * acquisition order, no matter which path leaves the scope.
 *
 * C++20, stdlib only. No globals, no statics: each guard talks only to
 * the log it was constructed with, so any number of logs may be live.
 */
#ifndef GUARD_HPP
#define GUARD_HPP

#include <string>
#include <vector>

using ActionLog = std::vector<std::string>;

class FileGuard {
public:
    FileGuard() noexcept;                         // inactive, journals nothing ever
    FileGuard(ActionLog& log, std::string path);  // appends "open <path>" now
    ~FileGuard();                                 // appends "close <path>" if still active
    FileGuard(FileGuard&&) noexcept;
    FileGuard& operator=(FileGuard&&) noexcept;
    FileGuard(const FileGuard&) = delete;         // copying a handle makes no sense
    FileGuard& operator=(const FileGuard&) = delete;
    bool active() const noexcept;
    const std::string& path() const noexcept;     // "" when inactive
    void release();                                // close early; safe to call again

private:
    ActionLog* log_ = nullptr;   // null <=> inactive
    std::string path_;
};

class LockGuard {
public:
    LockGuard() noexcept;
    LockGuard(ActionLog& log, std::string name);  // appends "lock <name>" now
    ~LockGuard();                                 // appends "unlock <name>" if still active
    LockGuard(LockGuard&&) noexcept;
