#include "sokoban.h"

#include <cctype>

namespace {
bool is_wall_at(const Sokoban *s, int x, int y) {
    if (x < 0 || y < 0 || x >= s->w || y >= s->h) return true; // grid edge
    return s->wall[y * s->w + x];
}
bool dir_delta(char d, int &dx, int &dy) {
    switch (std::tolower(static_cast<unsigned char>(d))) {
        case 'l': dx = -1; dy = 0; return true;
        case 'r': dx = 1;  dy = 0; return true;
        case 'u': dx = 0;  dy = -1; return true;
        case 'd': dx = 0;  dy = 1;  return true;
    }
    return false;
}
}

bool sb_load(Sokoban *s, const std::string &level) {
    *s = Sokoban{};  // reset: failed loads leave an unusable object

    std::vector<std::string> rows;
    std::string cur;
    for (char c : level) {
        if (c == '\n') { rows.push_back(cur); cur.clear(); }
        else cur.push_back(c);
    }
    if (!cur.empty()) rows.push_back(cur);

    int w = 0;
    for (auto &r : rows) w = std::max(w, (int)r.size());
    int h = (int)rows.size();

    Sokoban tmp;
    tmp.w = w; tmp.h = h;
    tmp.wall.assign(w * h, false);
    tmp.goal.assign(w * h, false);
    tmp.box.assign(w * h, false);

    int players = 0, boxes = 0, goals = 0;
    for (int y = 0; y < h; y++) {
        for (int x = 0; x < w; x++) {
            char c = x < (int)rows[y].size() ? rows[y][x] : ' ';
            switch (c) {
                case '#': tmp.wall[y*w+x] = true; break;
                case '.': tmp.goal[y*w+x] = true; goals++; break;
                case '$': tmp.box[y*w+x] = true; boxes++; break;
                case '*': tmp.box[y*w+x] = true; tmp.goal[y*w+x] = true; boxes++; goals++; break;
                case '@': tmp.px = x; tmp.py = y; players++; break;
                case '+': tmp.px = x; tmp.py = y; players++; tmp.goal[y*w+x] = true; goals++; break;
                default: break; // ' ' and anything else is floor
            }
        }
    }

    if (players != 1 || boxes < 1 || boxes != goals) return false;
    tmp.valid = true;
    *s = tmp;
    return true;
}
```

