int sb_move(Sokoban *s, char dir) {
    int dx, dy;
    if (!dir_delta(dir, dx, dy)) return -1;
    if (!s->valid) return 0;
    int nx = s->px + dx, ny = s->py + dy;
    if (is_wall_at(s, nx, ny)) return 0;
    bool pushed = false;
    if (s->box[ny * s->w + nx]) {
        int bx = nx + dx, by = ny + dy;
        if (is_wall_at(s, bx, by) || s->box[by * s->w + bx]) return 0;
        s->box[ny * s->w + nx] = false;
        s->box[by * s->w + bx] = true;
        pushed = true;
    }
    s->px = nx; s->py = ny;
    s->history.push_back({dx, dy, pushed});
    if (pushed) s->pushes++;
    return pushed ? 2 : 1;
}
```

