static bool parse_move(const std::string &tok, int *b, int *c) {
    // exactly one colon, at least one digit each side, all chars digits
    size_t colon = tok.find(':');
    if (colon == std::string::npos || colon == 0 || colon + 1 >= tok.size()) return false;
    if (tok.find(':', colon + 1) != std::string::npos) return false;
