bool ut_play(UTTT *g, int b, int c) {
    if (g->winner != 0) return false;
    if (!in_range(b) || !in_range(c)) return false;
    if (g->sub[b] != 0) return false;
    if (g->cells[b][c] != 0) return false;
    if (g->forced != -1 && g->forced != b) return false;

    int p = g->to_move;
    g->cells[b][c] = p;

    int bw = line_owner(g->cells[b]);
    if (bw != 0) {
        g->sub[b] = bw;
        ++g->closed;
    } else {
        bool full = true;
        for (int i = 0; i < 9; ++i) if (g->cells[b][i] == 0) { full = false; break; }
        if (full) { g->sub[b] = 3; ++g->closed; }
    }

    int mw = line_owner(g->sub);
    if (mw != 0) g->winner = mw;
    else if (g->closed == 9) g->winner = 3;

    g->forced = (g->sub[c] == 0) ? c : -1;
    g->to_move = 3 - p;
    return true;
}
