public sealed class FrequencyBot : IBot
{
    public string Name { get; }
    public FrequencyBot(string name) { Name = name; }
    public Move Next(IReadOnlyList<Move> opponentMoves)
    {
        int rock = 0, paper = 0, scissors = 0;
        foreach (var m in opponentMoves)
        {
            if (m == Move.Rock) rock++;
            else if (m == Move.Paper) paper++;
            else scissors++;
        }
        // ties resolve to the first move in Rock, Paper, Scissors order
        Move most = Move.Rock; int best = rock;
        if (paper > best) { most = Move.Paper; best = paper; }
        if (scissors > best) { most = Move.Scissors; }
        return Rules.Counter(most);
    }
}
