            var moveB = b.Next(historyA);
            string outcome;
            if (Rules.Beats(moveA, moveB)) { winsA++; outcome = a.Name; }
            else if (Rules.Beats(moveB, moveA)) { winsB++; outcome = b.Name; }
            else { draws++; outcome = "draw"; }
            transcript.Add($"R{i}: {a.Name} {Render(moveA)} vs {b.Name} {Render(moveB)} -> {outcome}");
            historyA.Add(moveA);
            historyB.Add(moveB);
        }
        return new MatchResult(winsA, winsB, draws, transcript);
    }
}
