            lines.Add($"RESULT {a.Name} {result.WinsA} {b.Name} {result.WinsB}");
            var sa = stats[a.Name]; var sb = stats[b.Name];
            sa.RoundWins += result.WinsA; sa.RoundLosses += result.WinsB;
            sb.RoundWins += result.WinsB; sb.RoundLosses += result.WinsA;
            if (result.WinsA > result.WinsB) { sa.Points += 3; sa.Wins++; sb.Losses++; }
            else if (result.WinsB > result.WinsA) { sb.Points += 3; sb.Wins++; sa.Losses++; }
            else { sa.Points++; sb.Points++; sa.Draws++; sb.Draws++; }
        }
        lines.Add("STANDINGS");
        var ordered = bots
            .OrderByDescending(b => stats[b.Name].Points)
            .ThenByDescending(b => stats[b.Name].RoundWins - stats[b.Name].RoundLosses)
            .ThenByDescending(b => stats[b.Name].RoundWins)
            .ThenBy(b => b.Name, StringComparer.Ordinal);
        int pos = 1;
        foreach (var b in ordered)
        {
            var s = stats[b.Name];
            lines.Add($"{pos}. {b.Name} pts={s.Points} w={s.Wins} d={s.Draws} l={s.Losses} rw={s.RoundWins} rl={s.RoundLosses}");
            pos++;
        }
        return string.Join('\n', lines);
    }
}
