private static IReadOnlyList<IBot> ParseRoster(string rosterText)
{
    var bots = new List<IBot>();
    var names = new HashSet<string>(StringComparer.Ordinal);
    foreach (var rawLine in rosterText.Split('\n'))
    {
        var line = rawLine.Trim();
        if (line.Length == 0 || line.StartsWith('#')) continue;
        var parts = line.Split(' ', StringSplitOptions.RemoveEmptyEntries);
        if (parts.Length < 2) throw new FormatException($"Malformed roster line: '{line}'.");
        var name = parts[0];
        var kind = parts[1];
        IBot bot = kind switch { ... };
        if (!names.Add(name)) throw new ArgumentException($"Duplicate bot name '{name}'.");
        bots.Add(bot);
    }
    if (bots.Count < 2) throw new ArgumentException("Roster must contain at least two bots.");
    return bots;
}
