Feedbacks.Score:

```csharp
using System.Text;

namespace WordleSolver;

public static class Feedbacks
{
    public static string Score(string guess, string answer)
    {
        ValidateWord(guess, nameof(guess));
        ValidateWord(answer, nameof(answer));

        var result = new char[5];
        var remaining = new int[26];

        // Greens first: exact matches consume their answer letter.
        for (var i = 0; i < 5; i++)
        {
            if (guess[i] == answer[i])
            {
                result[i] = 'G';
            }
            else
            {
                result[i] = '\0';
                remaining[answer[i] - 'a']++;
            }
        }

        // Then scan the unresolved guess letters left to right.
        for (var i = 0; i < 5; i++)
        {
            if (result[i] == 'G') continue;
            var slot = guess[i] - 'a';
            if (remaining[slot] > 0)
            {
                remaining[slot]--;
                result[i] = 'Y';
            }
            else
            {
                result[i] = 'B';
            }
        }

        return new string(result);
    }

    internal static void ValidateWord(string word, string paramName)
    {
        if (word is null || word.Length != 5 || !word.All(c => c is >= 'a' and <= 'z'))
            throw new ArgumentException("Word must be exactly five lowercase ASCII letters.", paramName);
    }
}
```

Note: '\0' placeholder — I use result[i] == 'G' check, so any non-'G' initial value works. Cleaner: use a bool array or set greens and track. Fine as is, but maybe use `result[i] != 'G'`. It's fine.

