        if (!_hasObserved) return _opener;
        if (_pool.Count == 0)
            throw new InvalidOperationException("No candidates remain.");
        return _pool[0];
    }

    public void Observe(string guess, string feedback)
    {
        if (feedback is null || feedback.Length != 5 || !feedback.All(c => c is 'G' or 'Y' or 'B'))
            throw new ArgumentException("Feedback must be five characters of G, Y, or B.", nameof(feedback));
        _hasObserved = true;
        _pool.RemoveAll(w => Feedbacks.Score(guess, w) != feedback);
    }

