```csharp
private static List<string> Parse(string candidateList)
{
    var words = new List<string>();
    var seen = new HashSet<string>(StringComparer.Ordinal);

    using var reader = new StringReader(candidateList ?? "");
    while (reader.ReadLine() is { } line)
    {
        var hash = line.IndexOf('#');
        if (hash >= 0) line = line[..hash];
        var word = line.Trim();
        if (word.Length == 0) continue;
        if (!IsValidWord(word))
            throw new FormatException($"Candidate word \"{word}\" must be exactly five lowercase ASCII letters.");
        if (!seen.Add(word))
            throw new ArgumentException($"Duplicate candidate word \"{word}\".", nameof(candidateList));
        words.Add(word);
    }

    words.Sort(StringComparer.Ordinal);
    return words;
}
```

