```csharp
namespace WordSearch;

public sealed class Lcg
{
    private long _state;

    public Lcg(int seed)
    {
        if (seed < 0) throw new ArgumentException("Seed must be non-negative.", nameof(seed));
        _state = seed;
    }

    public int Next()
    {
        _state = (_state * 1103515245L + 12345L) % 2147483648L;
        return (int)_state;
    }

    public int Rand(int k)
    {
        if (k <= 0) throw new ArgumentOutOfRangeException(nameof(k), "Modulus must be positive.");
        return Next() % k;
    }
}
```

