    public static IReadOnlyList<Placement> Find(string gridText, IReadOnlyList<string> words)
    {
        var rows = ParseGrid(gridText);
        var normalized = WordRules.Normalize(words);
        var found = new List<Placement>();
        foreach (var word in normalized)
        {
            for (var r = 0; r < rows.Count; r++)
                for (var c = 0; c < rows[0].Length; c++)
                    for (var d = 0; d < 8; d++)
                        if (Matches(rows, word, r, c, d))
                            found.Add(new Placement(word, r, c, Compass.Directions[d].Name));
        }
        found.Sort((a, b) => {
            var byWord = string.CompareOrdinal(a.Word, b.Word);
            if (byWord != 0) return byWord;
            if (a.Row != b.Row) return a.Row.CompareTo(b.Row);
            if (a.Col != b.Col) return a.Col.CompareTo(b.Col);
            return DirectionIndex(a.Direction).CompareTo(DirectionIndex(b.Direction));
        });
        return found;
    }
}
