private static bool TryPlace(char[,] grid, int height, int width, string word, int r, int c, int dr, int dc)
{
    for (var i = 0; i < word.Length; i++)
    {
        var rr = r + dr * i;
        var cc = c + dc * i;
        if (rr < 0 || rr >= height || cc < 0 || cc >= width) return false;
        var cell = grid[rr, cc];
        if (cell != '\0' && cell != word[i]) return false;
    }
    for (var i = 0; i < word.Length; i++)
        grid[r + dr * i, c + dc * i] = word[i];
    return true;
}
