using System.Threading.Channels;

namespace BagLine;

public sealed record Bag(string Tag, string Flight);

public sealed class MakeupCarousel
{
    private readonly Channel<Bag> _belt;

    public MakeupCarousel(int capacity)
    {
        if (capacity < 1)
            throw new ArgumentOutOfRangeException(nameof(capacity), capacity, "Belt capacity must be at least 1.");

        _belt = Channel.CreateBounded<Bag>(new BoundedChannelOptions(capacity)
        {
            SingleReader = true,
            SingleWriter = false,
            FullMode = BoundedChannelFullMode.Wait
        });
    }

    public Task PlaceAsync(Bag bag, CancellationToken ct = default)
        => _belt.Writer.WriteAsync(bag, ct).AsTask();

    public bool TryPlace(Bag bag) => _belt.Writer.TryWrite(bag);

    public void CloseFlight() => _belt.Writer.TryComplete();

    public async Task<IReadOnlyList<string>> LoadAsync(Func<Bag, Task<string>> loader)
    {
        var loaded = new List<string>();
        await foreach (var bag in _belt.Reader.ReadAllAsync())
            loaded.Add(await loader(bag));
        return loaded;
    }
}
```

