```csharp
public void Submit(string actor, DateTimeOffset at)
{
    if (Status != ClaimStatus.ReadyForSubmission)
        throw new InvalidClaimTransitionException(
            $"claim {Id} cannot transition from {Status} to Submitted");
    int nextVersion = checked(Version + 1);
    Status = ClaimStatus.Submitted;
    SubmittedBy = actor;
    SubmittedAt = at;
    Version = nextVersion;
}
```

