```csharp
namespace FerryHub;

/// <summary>
/// In-process event hub shared by the terminal modules. Handlers are plain
/// delegates keyed by exact event type; dispatch order is subscription order,
/// one failing handler never blocks the rest, and every publish runs against
/// a snapshot of the registrations taken when it started.
/// </summary>
public sealed class OpsHub
{
    private readonly List<Subscription> _registrations = new();

    /// <summary>Raised once per publish after the handlers have run.</summary>
    public event Action<string, int>? Dispatched;

    public Subscription Subscribe<TEvent>(Action<TEvent> handler)
    {
        ArgumentNullException.ThrowIfNull(handler);
        var subscription = new Subscription(typeof(TEvent), handler);
        _registrations.Add(subscription);
        return subscription;
    }

    public bool Unsubscribe(Subscription subscription)
    {
        ArgumentNullException.ThrowIfNull(subscription);
        return _registrations.Remove(subscription);
    }

    public PublishResult Publish<TEvent>(TEvent evt)
    {
        // Snapshot first: subscribe/unsubscribe during dispatch only affects
        // the NEXT publish, never the one in flight.
        var snapshot = _registrations.ToArray();
        var delivered = 0;
        List<Exception>? errors = null;

        foreach (var subscription in snapshot)
        {
            if (subscription.EventType != typeof(TEvent))
            {
                continue;
            }

            try
            {
                ((Action<TEvent>)subscription.Handler)(evt);
                delivered++;
            }
            catch (Exception ex)
            {
                // Iron rule: catch, collect, keep going.
                (errors ??= new List<Exception>()).Add(ex);
            }
        }

        Dispatched?.Invoke(typeof(TEvent).Name, delivered);
        return new PublishResult(delivered, (IReadOnlyList<Exception>?)errors ?? Array.Empty<Exception>());
    }
}
```

