/// <summary>
/// Money rendering for the remittance desk. Amounts are integer cents
/// everywhere; the printed form is "$D.CC" with no thousands separator.
/// </summary>
public static class MoneyFmt
{
    /// <summary>Formats integer cents as "$D.CC", culture-independent.</summary>
    public static string Format(long cents)
    {
        long dollars = cents / 100;
        long remainder = cents % 100;
        return string.Create(CultureInfo.InvariantCulture, $"${dollars}.{remainder:00}");
    }
}
