    public void Pause()
    {
        if (State != SubState.Active)
            throw new InvalidOperationException($"cannot pause {Id} in state {State}");
        State = SubState.Paused;
    }

    public void Resume()
    {
        if (State != SubState.Paused)
            throw new InvalidOperationException($"cannot resume {Id} in state {State}");
        State = SubState.Active;
    }

    public void Cancel()
    {
        if (State == SubState.Cancelled)
            throw new InvalidOperationException($"{Id} is already cancelled");
        State = SubState.Cancelled;
    }

    public long Renew()
    {
        if (State != SubState.Active)
            throw new InvalidOperationException($"cannot renew {Id} in state {State}");
        PaidThroughIssue += Plan.TermIssues;
        PaidCents += Plan.PriceCents;
        return Plan.PriceCents;
    }

    public void Skip(int issueNumber)
    {
        if (State != SubState.Active)
            throw new InvalidOperationException($"cannot skip on {Id} in state {State}");
        if (issueNumber < FirstIssue || issueNumber > PaidThroughIssue)
            throw new ArgumentException(string.Create(CultureInfo.InvariantCulture, $"issue {issueNumber} is outside the paid window of {Id}"));
        int at = _skipped.BinarySearch(issueNumber);
        if (at >= 0)
            throw new InvalidOperationException(string.Create(CultureInfo.InvariantCulture, $"issue {issueNumber} already skipped on {Id}"));
        _skipped.Insert(~at, issueNumber);
        PaidThroughIssue += 1;
    }

    public bool IsDeliverable(int issueNumber)
    {
        return State == SubState.Active
            && issueNumber >= FirstIssue
            && issueNumber <= PaidThroughIssue
            && _skipped.BinarySearch(issueNumber) < 0;
    }
}
