/// <summary>
/// Carrier batching...
/// </summary>
public static class Bundler
{
    public static IReadOnlyList<Bundle> BundlesFor(Publisher publisher, int issueNumber)
    {
        IReadOnlyList<Subscription> deliverable = publisher.DeliverableOn(issueNumber);

        // Group subscriber ids by route; the source list is Id-ordinal, so
        // ids stay ordinal within each route.
        var idsByRoute = new Dictionary<string, List<string>>(StringComparer.Ordinal);
        foreach (Subscription subscription in deliverable)
        {
            if (!idsByRoute.TryGetValue(subscription.Route, out List<string>? ids))
            {
                ids = new List<string>();
                idsByRoute.Add(subscription.Route, ids);
            }
            ids.Add(subscription.Id);
        }

        var routes = new List<string>(idsByRoute.Keys);
        routes.Sort(StringComparer.Ordinal);

        var bundles = new List<Bundle>();
        foreach (string route in routes)
        {
            List<string> ids = idsByRoute[route];
            int capacity = publisher.Routes.Capacity(route);
            int sequence = 0;
            for (int start = 0; start < ids.Count; start += capacity)
            {
                sequence += 1;
                int count = Math.Min(capacity, ids.Count - start);
                bundles.Add(new Bundle(route, sequence, ids.GetRange(start, count)));
            }
        }
        return bundles;
    }
}

/// <summary>One strapped carrier bundle: a consecutive chunk of one route.</summary>
public class Bundle
{
    public Bundle(string route, int sequence, IReadOnlyList<string> subscriberIds)
    {
        Route = route;
        Sequence = sequence;
        SubscriberIds = subscriberIds;
    }

    public string Route { get; }
    public int Sequence { get; }
    public string Label => Route + "-" + Sequence.ToString(System.Globalization.CultureInfo.InvariantCulture);
    public IReadOnlyList<string> SubscriberIds { get; }
}
