```csharp
public class InMemoryRepository<T, TKey> : IRepository<T, TKey>
    where T : class, IEntity<TKey>
    where TKey : notnull, IEquatable<TKey>
{
    private readonly Dictionary<TKey, T> _store = new();
    private readonly List<TKey> _order = new();

    public int Count => _store.Count;

    public void Add(T item)
    {
        if (_store.ContainsKey(item.Id))
            throw new DuplicateKeyException(item.Id);
        _store.Add(item.Id, item);
        _order.Add(item.Id);
    }

    public bool TryGet(TKey id, [MaybeNullWhen(false)] out T item) =>
        _store.TryGetValue(id, out item);

    public bool Remove(TKey id)
    {
        if (!_store.Remove(id))
            return false;
        _order.Remove(id);
        return true;
    }

    public IReadOnlyList<T> Snapshot()
    {
        var copy = new List<T>(_order.Count);
        foreach (var id in _order)
            copy.Add(_store[id]);
        return copy;
    }
}
```

